namespace ConsoleApp
{
    class Program
    {
        static void Main(string[] args)
        {
            var rsakey = RSA.Create();
            rsakey.KeySize = 2048;

            var rsaparameters = rsakey.ExportParameters(true);
            var rsaparametersString = JsonConvert.SerializeObject(rsaparameters, Formatting.Indented);

            Console.Write(rsaparametersString);

            Console.ReadKey();
        }
    }
}
